<script lang='ts'>import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminSystem, type AdminSystem} from '$lib/api';import StatusBadge from '$lib/components/StatusBadge.svelte';let d:AdminSystem|null=null;let loading=false;let error='';const load=async()=>{loading=true;error='';try{d=await fetchAdminSystem();}catch(e:any){error=e.message||'Erreur';}finally{loading=false;}};onMount(load);</script><AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Admin System" subtitle="Runtime, services, intégrations"/><button on:click={load}>Refresh</button>{#if loading}<p>Chargement…</p>{/if}{#if error}<p>{error}</p>{/if}{#if d}<AdminSection title="Services internes"><p>PostgreSQL <StatusBadge status={d?.services?.postgres||'error'}/></p><p>Redis <StatusBadge status={d?.services?.redis||'error'}/></p><p>NATS <StatusBadge status={d?.services?.nats||'not_configured'}/></p><p>ClickHouse <StatusBadge status={d?.services?.clickhouse||'not_configured'}/></p></AdminSection><AdminSection title="Intégrations"><p>YouTube <StatusBadge status={d?.integrations?.youtube||'not_configured'}/></p><p>Stripe <StatusBadge status={d?.integrations?.stripe||'not_configured'}/></p><p>SMTP <StatusBadge status={d?.integrations?.smtp||'not_configured'}/></p><p>Telegram <StatusBadge status={d?.integrations?.telegram||'not_configured'}/></p></AdminSection>{/if}{/if}</AppShell>
